dark.misc:
html body .data-footnote-backref {
  --font-weight: var(--link-weight);
  color: var(--text-faint);
}

html body .footnotes {
  background-color: rgba(0, 0, 0, 0);
  border-top-color: rgb(197, 197, 197);
  border-top-width: 0px;
  color: rgb(197, 197, 197);
}

html body .katex > .katex-html {
  font-family: MJXZERO, MJXTEX;
}

html body .katex-display {
  background-color: rgba(0, 0, 0, 0);
  border-bottom-color: rgb(197, 197, 197);
  border-bottom-left-radius: 0px;
  border-bottom-right-radius: 0px;
  border-bottom-width: 0px;
  border-left-color: rgb(197, 197, 197);
  border-left-width: 0px;
  border-right-color: rgb(197, 197, 197);
  border-right-width: 0px;
  border-top-color: rgb(197, 197, 197);
  border-top-left-radius: 0px;
  border-top-right-radius: 0px;
  border-top-width: 0px;
  color: rgb(197, 197, 197);
}

html body .katex-display > .katex {
  display: block;
  font-family: Aspekta, sans-serif, ui-sans-serif, -apple-system, BlinkMacSystemFont, system-ui, "Segoe UI", "Google Sans Flex", Roboto, "Inter Variable", Inter, "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol", sans-serif;
  text-align: center;
}

html body .katex-display > .katex > .katex-html {
  font-family: Aspekta, sans-serif, ui-sans-serif, -apple-system, BlinkMacSystemFont, system-ui, "Segoe UI", "Google Sans Flex", Roboto, "Inter Variable", Inter, "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol", sans-serif;
}

html body .navigation-progress {
  background-color: var(--status-bar-background);
}

html body .page-header h2.page-title {
  background: rgba(0, 0, 0, 0) none repeat scroll 0% 0% / auto padding-box border-box;
  background-color: rgba(0, 0, 0, 0);
  border-bottom-color: rgb(197, 197, 197);
  border-bottom-left-radius: 0px;
  border-bottom-right-radius: 0px;
  border-bottom-width: 0px;
  border-left-color: rgb(197, 197, 197);
  border-left-width: 0px;
  border-right-color: rgb(197, 197, 197);
  border-right-width: 0px;
  border-top-color: rgb(197, 197, 197);
  border-top-left-radius: 0px;
  border-top-right-radius: 0px;
  border-top-width: 0px;
  color: var(--text-normal);
  font-family: Aspekta, sans-serif, ui-sans-serif, -apple-system, BlinkMacSystemFont, system-ui, "Segoe UI", "Google Sans Flex", Roboto, "Inter Variable", Inter, "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol", sans-serif;
  font-size: 14px;
  font-weight: 400;
  line-height: 18.2px;
  margin-bottom: 0px;
  margin-left: 0px;
  margin-right: 0px;
  margin-top: 0px;
  padding-bottom: 0px;
  padding-left: 0px;
  padding-right: 0px;
  padding-top: 0px;
}

html body .spacer {
  background-color: rgba(0, 0, 0, 0);
}

html body abbr {
  color: rgb(197, 197, 197);
  text-decoration: underline dotted;
  text-decoration-style: dotted;
}

html body details {
  background-color: rgba(0, 0, 0, 0);
  border-bottom-color: rgb(197, 197, 197);
  border-bottom-left-radius: 0px;
  border-bottom-right-radius: 0px;
  border-bottom-width: 0px;
  border-left-color: rgb(197, 197, 197);
  border-left-width: 0px;
  border-right-color: rgb(197, 197, 197);
  border-right-width: 0px;
  border-top-color: rgb(197, 197, 197);
  border-top-left-radius: 0px;
  border-top-right-radius: 0px;
  border-top-width: 0px;
  margin-bottom: 0px;
  margin-left: 0px;
  margin-right: 0px;
  margin-top: 0px;
  padding-bottom: 0px;
  padding-left: 0px;
  padding-right: 0px;
  padding-top: 0px;
}

html body footer {
  opacity: 1;
}

html body input[type=text] {
  background-color: rgba(0, 0, 0, 0);
  border-bottom-color: rgb(247, 69, 69);
  border-bottom-left-radius: 0px;
  border-bottom-right-radius: 0px;
  border-bottom-style: solid;
  border-bottom-width: 0px;
  border-left-color: rgb(247, 69, 69);
  border-left-style: solid;
  border-left-width: 0px;
  border-right-color: rgb(247, 69, 69);
  border-right-style: solid;
  border-right-width: 0px;
  border-top-color: rgb(247, 69, 69);
  border-top-left-radius: 0px;
  border-top-right-radius: 0px;
  border-top-style: solid;
  border-top-width: 0px;
  color: var(--text-normal);
  font-family: var(--font-mono);
  padding-bottom: 4px;
  padding-left: 8px;
  padding-right: 8px;
  padding-top: 4px;
}

html body kbd {
  background-color: var(--code-background);
  border-bottom-color: rgb(247, 69, 69);
  border-bottom-left-radius: 0px;
  border-bottom-right-radius: 0px;
  border-bottom-width: 0px;
  border-left-color: rgb(247, 69, 69);
  border-left-width: 0px;
  border-right-color: rgb(247, 69, 69);
  border-right-width: 0px;
  border-top-color: rgb(247, 69, 69);
  border-top-left-radius: 0px;
  border-top-right-radius: 0px;
  border-top-width: 0px;
  color: var(--color-accent);
  font-family: var(--font-monospace);
  font-size: var(--code-size);
  padding-bottom: 0px;
  padding-left: 4px;
  padding-right: 4px;
  padding-top: 0px;
}

html body li.task-list-item input[type="checkbox"] {
  background-color: rgb(255, 255, 255);
  border-color: rgb(102, 102, 102);
  border-radius: 0px;
  border-width: 1px;
}

html body li.task-list-item input[type="checkbox"]:checked {
  background-color: var(--checkbox-color);
  border-color: rgba(0, 0, 0, 0);
}

html body progress {
  background-color: rgba(0, 0, 0, 0);
  border-bottom-color: rgb(197, 197, 197);
  border-bottom-left-radius: 0px;
  border-bottom-right-radius: 0px;
  border-bottom-width: 0px;
  border-left-color: rgb(197, 197, 197);
  border-left-width: 0px;
  border-right-color: rgb(197, 197, 197);
  border-right-width: 0px;
  border-top-color: rgb(197, 197, 197);
  border-top-left-radius: 0px;
  border-top-right-radius: 0px;
  border-top-width: 0px;
  height: 6px;
}

html body sub {
  color: rgb(197, 197, 197);
  font-size: 13.3333px;
  vertical-align: sub;
}

html body summary {
  background-color: rgba(0, 0, 0, 0);
  color: rgb(197, 197, 197);
  font-weight: 500;
  padding-bottom: 0px;
  padding-left: 0px;
  padding-right: 0px;
  padding-top: 0px;
}

html body sup {
  color: rgb(197, 197, 197);
  font-size: 13.3333px;
  vertical-align: super;
}

html body ul.tags > li {
  --font-weight: var(--link-weight);
  background-color: var(--tag-background);
  border-bottom-color: rgba(247, 69, 69, 0.15);
  border-bottom-left-radius: 24.5px;
  border-bottom-right-radius: 24.5px;
  border-bottom-style: solid;
  border-bottom-width: 0px;
  border-left-color: rgba(247, 69, 69, 0.15);
  border-left-style: solid;
  border-left-width: 0px;
  border-right-color: rgba(247, 69, 69, 0.15);
  border-right-style: solid;
  border-right-width: 0px;
  border-top-color: rgba(247, 69, 69, 0.15);
  border-top-left-radius: 24.5px;
  border-top-right-radius: 24.5px;
  border-top-style: solid;
  border-top-width: 0px;
  color: var(--tag-color);
}
